INSERT INTO `about` (`about_id`, `title`, `image`, `description`, `_token`, `created_at`, `updated_at`) VALUES
(2, 'Who We Are?', '5d8f93d75576aadult-apartment-architecture-2460648.jpg', '<p>Zouple, during its long journey, is dedicated to unite premium and unique accessories to its family with a common passion. It is dedicated to make unique designs that could be available to everybody.</p>\r\n\r\n<p>We are creating a convenient and inspiring experience for our customers. Our brands engage with customers in online as well as in social media and other creative places. Shopping should be easy and relevant regardless of where, when and how customers choose to shop. We are also developing the presentation and functionalities online while personalising our sites.</p>', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-26 12:30:49', '2019-09-28 17:09:43'),
(3, 'What is our service?', '5d8f94fd53f82bag-book-briefcase-2977304(1).jpg', '<p>Zouple is one of the latest brand in India that allows its customers to customize their own shirt in few steps in less then one minute. Now you no need to search your style for a long time and then too lasts in compromising with less. Make it your own and we will deliver it to your doorstep.</p>\r\n\r\n<p>Brand is dealing in premium quality handicrafts and artificial jewellery with unique &amp; attractive designs.</p>', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-26 12:50:57', '2019-09-28 17:14:37'),
(4, 'Our Values', '5d8f960b096ddbeautiful-beauty-brunette-2755075.jpg', '<p><strong>Customer first:</strong>&nbsp;Customers take precedence over all else, always.</p>\r\n\r\n<p><strong>Culture and teamwork:</strong>&nbsp;Preserve culture and believe in teamwork.</p>\r\n\r\n<p><strong>Creativity and innovation:</strong>&nbsp;Driven by innovation and creativity, we focus on smarter approaches and latest fashions</p>\r\n\r\n<p><strong>Passion for excellence:&nbsp;</strong>In all our pursuits, we ceaselessly strive for excellence.</p>', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-26 12:51:13', '2019-09-28 17:19:07');
