(189, 'rutile-quartz-mala-148sm8225-1', 0, '[\"3\",\"13\"]', 2, 'JAJ-JAG-14/8SM8225', 'Rutile Quartz Mala [14/8SM8225]', '3', '8225', '5d829776dca30IMG_8226.JPG', '[\"5d829776dcdbdIMG_8225.JPG\",\"5d829776dcf89IMG_8227.JPG\",\"5d829776dd10bIMG_8228.JPG\",\"5d829776dd29dIMG_8229.JPG\"]', '<p>A beautiful Rutilated Quartz mala.</p>\r\n\r\n<p><strong>Rutilated Quartz</strong> is an illuminator for the soul, promoting spiritual growth. It cleanses and energises the aura. Draws off negative energy and disease, letting go of the past. <strong>Rutilated Quartz</strong> gives protection against the ill thoughts of others.</p>', '<p><strong>Brand:</strong>&nbsp;Zouple</p>\r\n\r\n<p><strong>Code: JAJ-JAG-14/8SM8225</strong></p>\r\n\r\n<hr />\r\n<p><strong>Occasion</strong>:Ethnic&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Stone: Rutile Quartz</strong> &nbsp; &nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Type</strong>: Mala&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <strong>Trends</strong>: Handicrafted&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;</strong></p>\r\n\r\n<p><strong>Content:</strong>&nbsp;One Mala</p>\r\n\r\n<p>&nbsp;</p>', '<p><strong>Care Instructions:</strong></p>\r\n\r\n<ul>\r\n	<li>Wipe your jewellery with a soft cloth after every use</li>\r\n	<li>Always store your jewellery in a flat box to avoid accidental scratches</li>\r\n	<li>Keep sprays and perfumes away from your jewellery</li>\r\n	<li>Do not soak your jewellery in water</li>\r\n	<li>Clean your jewellery using a soft brush, dipped in jewellery cleaning solution only</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'NO', 'NO', 'ACTIVE', 'INSTOCK', 'Rutile Quartz Mala [14/8SM8225]', 'Rutile Quartz Mala [14/8SM8225]', 'Rutile Quartz Mala [14/8SM8225]', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-28 20:20:35', '2019-09-18 20:45:42'),
(190, 'moonstone-mala-148sm8231-1', 0, '[\"3\",\"13\"]', 2, 'JAJ-JAG-14/8SM8231', 'Moonstone Mala [14/8SM8231]', '3', '8231', '5d829abbe148eIMG_8230.JPG', '[\"5d829abbe16e8IMG_8231.JPG\",\"5d829abbe1993IMG_8232.JPG\",\"5d829abbe1b2aIMG_8233.JPG\",\"5d829abbe1cd4IMG_8234.JPG\",\"5d829abbe1e86IMG_8235.JPG\"]', '<p>A beautiful Moonstone mala.</p>\r\n\r\n<p>A stone for &ldquo;new beginnings&rdquo;, <strong>Moonstone</strong> is a stone of inner growth and strength. It soothes emotional instability and stress, and stabilises the emotions, providing calmness. <strong>Moonstone</strong> enhances intuition, promotes inspiration, success and good fortune in love and business matters.</p>', '<p><strong>Brand:</strong>&nbsp;Zouple</p>\r\n\r\n<p><strong>Code: JAJ-JAG-14/8SM8231</strong></p>\r\n\r\n<hr />\r\n<p><strong>Occasion</strong>:Ethnic&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Stone: Moonstone</strong> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Type</strong>: Mala&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Trends</strong>: Handicrafted&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;</strong></p>\r\n\r\n<p><strong>Content:</strong>&nbsp;One Mala</p>\r\n\r\n<p>&nbsp;</p>', '<p><strong>Care Instructions:</strong></p>\r\n\r\n<ul>\r\n	<li>Wipe your jewellery with a soft cloth after every use</li>\r\n	<li>Always store your jewellery in a flat box to avoid accidental scratches</li>\r\n	<li>Keep sprays and perfumes away from your jewellery</li>\r\n	<li>Do not soak your jewellery in water</li>\r\n	<li>Clean your jewellery using a soft brush, dipped in jewellery cleaning solution only</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'NO', 'NO', 'ACTIVE', 'INSTOCK', 'Moonstone Mala [14/8SM8231]', 'Moonstone Mala [14/8SM8231]', 'Moonstone Mala [14/8SM8231]', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-28 20:21:16', '2019-09-18 20:59:39');
INSERT INTO `products` (`product_id`, `slug`, `product_shipping`, `category`, `vendor_id`, `product_sku`, `product_title`, `product_gst`, `product_hsn`, `product_header_image`, `product_images`, `product_description`, `product_specification`, `product_addition_information`, `featured_product`, `new_arrivals`, `is_active`, `in_stock`, `meta_title`, `meta_keyword`, `meta_description`, `_token`, `updated_at`, `created_at`) VALUES
(191, 'white-chalcedony-mala-52-faces-148sm8238-1', 0, '[\"3\",\"13\"]', 2, 'JAJ-JAG-14/8SM8238', 'White Chalcedony Mala, 52 Faces [14/8SM8238]', '3', '8238', '5d829bccaf0a9IMG_8237.JPG', '[\"5d829bccaf2f3IMG_8237.JPG\",\"5d829bccaf4a6IMG_8238.JPG\",\"5d829bccaf7a3IMG_8240.JPG\",\"5d829bccaf91dIMG_8241.JPG\",\"5d829bccafa76IMG_8242.JPG\"]', '<p>A beautiful Chalcedony mala.</p>\r\n\r\n<p>Chalcedony protects against negative influences,&nbsp;this gemstone increases energy and brings emotional balance. Chalcedony comes in many different colors including white, blue, gray, green, yellow, red, brown, pink, purple, and black. Each color activates healing from a different level.</p>\r\n\r\n<p>Chalcedony heals by warding off negative energy such as hostility and sadness, it boosts confidence and stimulates enthusiasm. This &ldquo;Stone of Generosity&rdquo; encourages kindness, understanding, unity, and brotherhood.</p>', '<p><strong>Brand:</strong>&nbsp;Zouple</p>\r\n\r\n<p><strong>Code:</strong> <strong>JAJ-JAG-14/8SM8238</strong></p>\r\n\r\n<hr />\r\n<p><strong>Occasion</strong>:Ethnic&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Stone: White Chalcedony</strong> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Type</strong>: Mala&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Trends</strong>: Handicrafted&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;</strong></p>\r\n\r\n<p><strong>Content:</strong>&nbsp;One Mala</p>\r\n\r\n<p>&nbsp;</p>', '<p><strong>Care Instructions:</strong></p>\r\n\r\n<ul>\r\n	<li>Wipe your jewellery with a soft cloth after every use</li>\r\n	<li>Always store your jewellery in a flat box to avoid accidental scratches</li>\r\n	<li>Keep sprays and perfumes away from your jewellery</li>\r\n	<li>Do not soak your jewellery in water</li>\r\n	<li>Clean your jewellery using a soft brush, dipped in jewellery cleaning solution only</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'NO', 'NO', 'ACTIVE', 'INSTOCK', 'White Chalcedony Mala [14/8SM8238]', 'White Chalcedony Mala [14/8SM8238]', 'White Chalcedony Mala [14/8SM8238]', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-28 20:21:59', '2019-09-18 21:04:12'),
(192, 'rose-quartz-mala-52-faces-148sm8244-1', 0, '[\"3\",\"13\"]', 2, 'JAJ-JAG-14/8SM8244', 'Rose Quartz Mala, 52 Faces [14/8SM8244]', '3', '8244', '5d829cdf6a349IMG_8243.JPG', '[\"5d829cdf6a5d7IMG_8243.JPG\",\"5d829cdf6a7a3IMG_8244.JPG\",\"5d829cdf6aad2IMG_8246.JPG\",\"5d829cdf6ae13IMG_8247.JPG\",\"5d829cdf6afc3IMG_8248.JPG\",\"5d829cdf6b164IMG_8249.JPG\"]', '<p>A beautiful Rose Quartz mala with 52 faces.</p>\r\n\r\n<p><strong>Rose Quartz</strong> is the stone of universal love. It restores trust and harmony in relationships, encouraging unconditional love. <strong>Rose Quartz</strong> purifies and opens the heart at all levels to promote love, self-love, friendship, deep inner healing and feelings of peace.</p>', '<p><strong>Brand:</strong>&nbsp;Zouple</p>\r\n\r\n<p><strong>Code: JAJ-JAG-14/8SM8244</strong></p>\r\n\r\n<hr />\r\n<p><strong>Occasion</strong>:Ethnic&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Stone: Rose Quartz, 52 Faces</strong>&nbsp; &nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Type</strong>: Mala&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Trends</strong>: Handicrafted&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;</strong></p>\r\n\r\n<p><strong>Content:</strong>&nbsp;One Mala</p>\r\n\r\n<p>&nbsp;</p>', '<p><strong>Care Instructions:</strong></p>\r\n\r\n<ul>\r\n	<li>Wipe your jewellery with a soft cloth after every use</li>\r\n	<li>Always store your jewellery in a flat box to avoid accidental scratches</li>\r\n	<li>Keep sprays and perfumes away from your jewellery</li>\r\n	<li>Do not soak your jewellery in water</li>\r\n	<li>Clean your jewellery using a soft brush, dipped in jewellery cleaning solution only</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'NO', 'NO', 'ACTIVE', 'INSTOCK', 'Rose Quartz Mala, 52 Faces [14/8SM8244]', 'Rose Quartz Mala, 52 Faces [14/8SM8244]', 'Rose Quartz Mala, 52 Faces [14/8SM8244]', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-28 20:23:17', '2019-09-18 21:08:47'),
(193, 'multi-colour-semi-precious-mala-52-faces-148sm8250-1', 0, '[\"3\",\"13\"]', 2, 'JAJ-JAG-14/8SM8250', 'Multi Colour Semi Precious Mala, 52 Faces [14/8SM8250]', '3', '8250', '5d829e0293765IMG_8250.JPG', '[\"5d829e02939c3IMG_8250.JPG\",\"5d829e0293bafIMG_8251.JPG\",\"5d829e0293f84IMG_8252.JPG\",\"5d829e0294352IMG_8254.JPG\",\"5d829e02945abIMG_8255.JPG\",\"5d829e02947a0IMG_8256.JPG\"]', '<p>This is a Multicolour semi precious stone mala. Wear it with matching style and flaunt in family functions and parties.</p>', '<p><strong>Brand:</strong>&nbsp;Zouple</p>\r\n\r\n<p><strong>Code: JAJ-JAG-14/8SM8250</strong></p>\r\n\r\n<hr />\r\n<p><strong>Occasion</strong>:Ethnic&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Stone: Mulicolour Semi Precious</strong> &nbsp; &nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n\r\n<p><strong>Type</strong>: Mala&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>Trends</strong>: Handicrafted&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;</strong></p>\r\n\r\n<p><strong>Content:</strong>&nbsp;One Mala</p>\r\n\r\n<p>&nbsp;</p>', '<p><strong>Care Instructions:</strong></p>\r\n\r\n<ul>\r\n	<li>Wipe your jewellery with a soft cloth after every use</li>\r\n	<li>Always store your jewellery in a flat box to avoid accidental scratches</li>\r\n	<li>Keep sprays and perfumes away from your jewellery</li>\r\n	<li>Do not soak your jewellery in water</li>\r\n	<li>Clean your jewellery using a soft brush, dipped in jewellery cleaning solution only</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'NO', 'NO', 'ACTIVE', 'INSTOCK', 'Multi Colour Semi Precious Mala, 52 Faces [14/8SM8250]', 'Multi Colour Semi Precious Mala, 52 Faces [14/8SM8250]', 'Multi Colour Semi Precious Mala, 52 Faces [14/8SM8250]', 'us7qm8dWCZWEB6v8zJ1GFkJwnRkzMx0FDOytb7vQ', '2019-09-28 20:23:59', '2019-09-18 21:13:38'),
